+      model: 'gpt-5.1',
+      options: { prompt: 'hi', model: 'gpt-5.1', mode: 'api' },
+    });
+    readLogMock.mockResolvedValueOnce('Answer: hello');
+    getPathsMock.mockResolvedValueOnce({
+      dir: '/tmp',
+      metadata: '/tmp/meta.json',
+      log: '/tmp/output.log',
+      request: '/tmp/request.json',
+    });
